func isPGAcctSelected(mappings map[uint]*models.PaymentAccountingMapping, gwID uint, field string, accountID uint) bool {
	m, ok := mappings[gwID]
	if !ok || m == nil {
		return false
	}
	var val *uint
	switch field {
	case "clearing_account_id":
		val = m.ClearingAccountID
	case "fee_expense_account_id":
		val = m.FeeExpenseAccountID
	case "refund_account_id":
		val = m.RefundAccountID
	case "payout_bank_account_id":
		val = m.PayoutBankAccountID
	}
	return val != nil && *val == accountID
}

